**Input:**

```json
db.movies.aggregate([{
  "$search": {
    "text": {
      "path": "title",
      "query": "men",
      "score": {
        "function": {
          "log": {
            "path": {
              "value": "imdb.rating",
              "undefined": 10
            }
          }
        }
      }
    },
    "scoreDetails": true
  }
},
{
  $limit: 5
},
{
  $project: {
    "_id": 0,
    "title": 1,
    "score": { "$meta": "searchScore" },
    "scoreDetails": {"$meta": "searchScoreDetails"}
  }
}])
```

